package ru.memearena.media.api;
import jakarta.validation.constraints.NotNull; import org.springframework.core.io.InputStreamResource; import org.springframework.http.*; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import ru.memearena.media.application.MediaService; import java.util.UUID;
@Validated @RestController @RequestMapping("/api/v1/media") public class MediaController { private final MediaService service; public MediaController(MediaService service){this.service=service;} @PostMapping(value="/images",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) public ResponseEntity<MediaUploadResponse> upload(@RequestParam @NotNull UUID userId,@RequestPart MultipartFile file){var r=service.upload(userId,file); return ResponseEntity.status(HttpStatus.CREATED).body(MediaUploadResponse.of(r.asset(),r.duplicateDetected()));} @GetMapping("/{mediaId}/content") public ResponseEntity<InputStreamResource> content(@PathVariable UUID mediaId,@RequestHeader(value="If-None-Match",required=false) String inm){var c=service.content(mediaId); if(c.etag().equals(inm)) return ResponseEntity.status(HttpStatus.NOT_MODIFIED).eTag(c.etag()).build(); return ResponseEntity.ok().contentType(MediaType.parseMediaType(c.contentType())).contentLength(c.sizeBytes()).eTag(c.etag()).cacheControl(CacheControl.maxAge(365,java.util.concurrent.TimeUnit.DAYS).cachePublic()).body(new InputStreamResource(c.stream()));} }
